useEffect(() => {
  if (players.length === 0 || resultSaved || !userId) return;
  const sorted = [...players].sort((a, b) => b.score - a.score);
  const myRankLocal = sorted.findIndex(p => p.playerId === userId) + 1;
  const isWin = myRankLocal === 1;
  const isLast = myRankLocal === players.length;
  saveMatchResult(userId, isWin, isLast, players.length);
  setResultSaved(true);
}, [players.length]);

async function saveMatchResult(uid: string, won: boolean, isLast: boolean, total: number) {
  try {
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const db = require('@react-native-firebase/firestore').default();
    const ref = db.collection('duel_profiles').doc(uid);
    const snap = await ref.get();

    const xpDelta = won ? 50 : 15;
    const correctCount = players.find(p => p.playerId === uid)?.answers.filter((a: { isCorrect: boolean }) => a.isCorrect).length ?? 0;

    if (!snap.exists) {
      // Создаём профиль с нуля
      await ref.set({
        userId: uid,
        displayName: 'Игрок',
        avatarId: '1',
        rank: { tier: 'bronze', level: 'I', stars: won ? 1 : 0 },
        xp: xpDelta,
        stats: {
          matchesPlayed: 1,
          matchesWon: won ? 1 : 0,
          totalScore: 0,
          winStreak: won ? 1 : 0,
          bestWinStreak: won ? 1 : 0,
        },
        updatedAt: Date.now(),
      });
      return;
    }

    const data = snap.data();
    const curStars: number = data.rank?.stars ?? 0;
    const curTier: string = data.rank?.tier ?? 'bronze';
    const curLevel: string = data.rank?.level ?? 'I';
    const curStreak: number = data.stats?.winStreak ?? 0;
    const bestStreak: number = data.stats?.bestWinStreak ?? 0;

    // Подсчёт звёздочек
    let newStars = curStars + (won ? 1 : isLast ? -1 : 0);
    let newTier = curTier;
    let newLevel = curLevel;

    const LEVELS = ['I', 'II', 'III'];
    const TIERS = ['bronze', 'silver', 'gold', 'platinum', 'diamond', 'master', 'grandmaster', 'legend'];

    if (newStars >= 3) {
      newStars = 0;
      const li = LEVELS.indexOf(curLevel);
      if (li < LEVELS.length - 1) {
        newLevel = LEVELS[li + 1];
      } else {
        newLevel = LEVELS[0];
        const ti = TIERS.indexOf(curTier);
        if (ti < TIERS.length - 1) newTier = TIERS[ti + 1];
      }
    } else if (newStars < 0) {
      newStars = 2;
      const li = LEVELS.indexOf(curLevel);
      if (li > 0) {
        newLevel = LEVELS[li - 1];
      } else if (TIERS.indexOf(curTier) > 0) {
        newTier = TIERS[TIERS.indexOf(curTier) - 1];
        newLevel = LEVELS[LEVELS.length - 1];
      } else {
        newStars = 0; // минимум bronze I 0 звёзд
      }
    }

    const newStreak = won ? curStreak + 1 : 0;

    await ref.update({
      'rank.tier': newTier,
      'rank.level': newLevel,
      'rank.stars': newStars,
      xp: (data.xp ?? 0) + xpDelta,
      'stats.matchesPlayed': (data.stats?.matchesPlayed ?? 0) + 1,
      'stats.matchesWon': (data.stats?.matchesWon ?? 0) + (won ? 1 : 0),
      'stats.totalScore': (data.stats?.totalScore ?? 0) + (players.find(p => p.playerId === uid)?.score ?? 0),
      'stats.winStreak': newStreak,
      'stats.bestWinStreak': Math.max(bestStreak, newStreak),
      updatedAt: Date.now(),
    });
  } catch {}
}
